mapper.update:
UPDATE regularization_application
formal_salary = #{formalSalary}, probation_summary = #{probationSummary}, supervisor_comment = #{supervisorComment}, status = #{status},
WHERE id = #{id}

mapper.select:
SELECT ra.*, e.name AS employee_name, e.dept_id, d.dept_name, p.position_name, e.entry_date AS hire_date, e.regular_date AS probation_end_date, su.username AS submitter_name FROM regularization_application ra JOIN employee e ON ra.employee_id = e.id LEFT JOIN department d ON e.dept_id = d.id LEFT JOIN position p ON e.position_id = p.id LEFT JOIN sys_user su ON ra.submitter_id = su.id
AND ra.status = #{status}
AND e.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY ra.create_time DESC LIMIT #{offset}, #{size}

SELECT COUNT(*) FROM regularization_application ra JOIN employee e ON ra.employee_id = e.id
AND ra.status = #{status}
AND e.name LIKE CONCAT('%', #{keyword}, '%')
